#!/usr/bin/env node
// gguf-forge-qwen35-parity.test.mjs — NUMERICAL parity (S4.7) of the qwen35 gated-DeltaNet linear layer
// (gguf-forge-qwen35.mjs) vs HuggingFace's reference Qwen3NextGatedDeltaNet, on identical weights + input.
// The fixture (gguf-forge-qwen35-parity.fixture.json) was generated by gguf-forge-qwen35-parity.gen.py:
// a tiny-config HF layer (torch reference path, no FLA) → its weights mapped to the GGUF/forge layout
// (in_proj_qkvz → contiguous attn_qkv + attn_gate, in_proj_ba → ssm_alpha/ssm_beta, conv1d, A_log, dt_bias,
// norm, out_proj) + a fixed input + the reference output. This is the gate that turns "plausible" into
// "correct": it caught a real bug (missing qk-L2-norm + q·1/√d scale) which is now fixed.
//
// Pass: every token cosine > 0.9999 AND max relative-L2 < 1e-3 (observed ~1e-6 — float rounding).
// Regenerate the fixture: python holo-apps/apps/q/forge/gguf-forge-qwen35-parity.gen.py
//
// Usage: node holo-apps/apps/q/forge/gguf-forge-qwen35-parity.test.mjs

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import { qwen35LinearLayer, newLayerState } from "./gguf-forge-qwen35.mjs";

const here = dirname(fileURLToPath(import.meta.url));
const ref = JSON.parse(readFileSync(join(here, "gguf-forge-qwen35-parity.fixture.json"), "utf8"));
const F = (a) => Float32Array.from(a);
const D = ref.dims, W = Object.fromEntries(Object.entries(ref.W).map(([k, v]) => [k, F(v)]));
const xSeq = ref.x.map(F), yRef = ref.y.map(F);

const r = qwen35LinearLayer(W, D, xSeq, newLayerState(D), { inputNormed: true });

const cos = (a, b) => { let d = 0, na = 0, nb = 0; for (let i = 0; i < a.length; i++) { d += a[i] * b[i]; na += a[i] * a[i]; nb += b[i] * b[i]; } return d / (Math.sqrt(na) * Math.sqrt(nb) + 1e-30); };
const relL2 = (a, b) => { let e = 0, n = 0; for (let i = 0; i < a.length; i++) { e += (a[i] - b[i]) ** 2; n += b[i] * b[i]; } return Math.sqrt(e / (n + 1e-30)); };

let minCos = 1, maxRel = 0;
const per = [];
for (let t = 0; t < yRef.length; t++) { const c = cos(r.ySeq[t], yRef[t]), e = relL2(r.ySeq[t], yRef[t]); minCos = Math.min(minCos, c); maxRel = Math.max(maxRel, e); per.push({ t, cos: +c.toFixed(6), relL2: e }); }

const witnessed = minCos > 0.9999 && maxRel < 1e-3;
writeFileSync(join(here, "gguf-forge-qwen35-parity.test.result.json"), JSON.stringify({
  spec: "qwen35 gated-DeltaNet linear layer is NUMERICALLY EXACT vs HF Qwen3NextGatedDeltaNet (same weights+input): contiguous q|k|v split, causal depthwise conv1d+SiLU (no bias), head-group repeat_interleave expansion, per-head qk L2-norm + q·1/√d scale, decay g=-exp(A_log)·softplus(a+dt_bias), gated delta-rule recurrence, gated RMSNorm with z, out_proj. Caught+fixed a missing qk-L2-norm. min cosine and max relative-L2 across tokens recorded below.",
  authority: "HF transformers modeling_qwen3_next (torch reference path) · fixture via gguf-forge-qwen35-parity.gen.py",
  minCosine: minCos, maxRelL2: maxRel, perToken: per, witnessed,
}, null, 2) + "\n");

for (const p of per) console.log(`  t=${p.t}  cos=${p.cos.toFixed(6)}  relL2=${p.relL2.toExponential(2)}`);
console.log(`min cosine=${minCos.toFixed(6)}  max relL2=${maxRel.toExponential(2)}`);
console.log(`VERDICT : ${witnessed ? "WITNESSED ✓ qwen35 linear layer is numerically exact to HF (S4.7 layer parity)" : "NOT WITNESSED"}`);
process.exit(witnessed ? 0 : 1);
